import React from 'react';
import s from './Mass.module.css'

const Mass = (props) => {

    let newMessageElement = React.createRef();

    let sendMessage = () => {
        let text = newMessageElement.current.value;
        alert(text)
    }

    return (
        <div>
            <div className={s.mass}>
                {props.message}
            </div>
            <div>
            <div>
                <textarea placeholder="Please,wright" className={s.textarea} ref={newMessageElement}>
                    ...
    </textarea>
            </div>
            <div className={s.but}>
                <button onClick={sendMessage}>send</button>
            </div>
            </div>
        </div>
    )
}
export default Mass;
